<script>
    (function($) {
        $(document).on('ready', function() {
            const productIcon = '<?php echo get_template_directory_uri(); ?>/assets/images/connect-drive/connect-drive.png';

            var handler = FS.Checkout.configure({
                plugin_id: '9618',
                plan_id: '16186',
                public_key: 'pk_eb27e7eaa4f2692b385aec28288f2',
                image: productIcon,
            });

            // Handle all buy button clicks dynamically
            $('.buy-btn-pro').on('click', function(e) {
                e.preventDefault();

                var $card = $(this).closest('.price-table');
                // var license = $card.find('[data-license]').attr('data-license');
                var license = $('.license-menu .list-item.active').data('license');
                var planName = $card.find('li').text();

                // assign product info
                const productInfo = {
                    productIcon: productIcon,
                    planName: planName,
                    productName: "Integrate Google Drive",
                    docs: "https://softlabbd.com/docs-category/integrate-connect-drive-docs/",
                    video: "https://www.youtube.com/watch?v=3RqCA7J9HB4&list=PLaR5hjDXnXZyQI6LU-1Ijz_x9vkXQop7I",
                    productDescription: "All-in-One Google Drive Integration for WordPress",
                };

                handler.open({
                    name: planName,
                    licenses: license,
                    purchaseCompleted: function(response) {
                        setTimeout(function() {
                            // assign productInfo to response
                            response.productInfo = productInfo;

                            // data 
                            const data = window.btoa(JSON.stringify(response));

                            // redirect
                            window.location.href = "<?php echo site_url('/thank-you'); ?>?data=" + data;
                        }, 2000);
                    },
                    success: function(response) {
                        console.log("Purchase Successful:", response);
                    }
                });
            });
        });
    })(jQuery);
</script>